+    /// Q3_K block structure (256 elements per block, 110 bytes)
+    /// Layout: hmask[32] + qs[64] + scales[12] + d[2]
+    const Q3_K_BLOCK = extern struct {
+        hmask: [32]u8, // high bit mask
+        qs: [64]u8, // 2-bit quants (low 2 bits)
+        scales: [12]u8, // quantized scales
+        d: u16, // FP16 super-scale
+    };
+
+    /// Dequantize Q3_K tensor to BF16
+    /// Reference: llama.cpp dequantize_row_q3_K (exact port)
+    fn dequantizeQ3_K(self: *Self, info: GGUFTensorInfo, dest: []BF16) !void {
+        const src = self.getTensorData(info);
+        const n_elements = info.numElements();
+
+        if (dest.len < n_elements) return error.DestBufferTooSmall;
+
+        const QK_K = 256;
+        const nb = n_elements / QK_K;
+
+        const kmask1: u32 = 0x03030303;
+        const kmask2: u32 = 0x0f0f0f0f;
+
+        const blocks: []const Q3_K_BLOCK = @as([*]const Q3_K_BLOCK, @ptrCast(@alignCast(src.ptr)))[0..nb];
+
+        for (blocks, 0..) |block, block_idx| {
+            const d_all = f16ToF32(block.d);
+            const y_base: usize = block_idx * QK_K;
+
+            // Decode scales using llama.cpp's exact bitmask method
+            var aux: [4]u32 = .{ 0, 0, 0, 0 };
+            @memcpy(std.mem.asBytes(&aux)[0..12], &block.scales);
+
+            const tmp = aux[2];
+            aux[2] = ((aux[0] >> 4) & kmask2) | (((tmp >> 4) & kmask1) << 4);
+            aux[3] = ((aux[1] >> 4) & kmask2) | (((tmp >> 6) & kmask1) << 4);
+            aux[0] = (aux[0] & kmask2) | (((tmp >> 0) & kmask1) << 4);
+            aux[1] = (aux[1] & kmask2) | (((tmp >> 2) & kmask1) << 4);
+
+            const scales: *const [16]i8 = @ptrCast(&aux);
+
+            var y_idx: usize = y_base;
+            var q_ptr: usize = 0;
+            var is: usize = 0;
+            var m: u8 = 1;
+
+            // Process 256 elements in two 128-element chunks
+            for (0..2) |_| {
+                var shift: u3 = 0;
+                for (0..4) |_| {
+                    const dl: f32 = d_all * @as(f32, @floatFromInt(@as(i32, scales[is]) - 32));
+                    is += 1;
+
+                    for (0..16) |l| {
+                        const q_val: i8 = @as(i8, @intCast((block.qs[q_ptr + l] >> shift) & 3));
+                        const h_sub: i8 = if ((block.hmask[l] & m) != 0) 0 else 4;
+                        dest[y_idx] = f32ToBf16(dl * @as(f32, @floatFromInt(q_val - h_sub)));
+                        y_idx += 1;
+                    }
+
+                    const dl2: f32 = d_all * @as(f32, @floatFromInt(@as(i32, scales[is]) - 32));
+                    is += 1;
+
+                    for (0..16) |l| {
+                        const q_val: i8 = @as(i8, @intCast((block.qs[q_ptr + 16 + l] >> shift) & 3));
+                        const h_sub: i8 = if ((block.hmask[16 + l] & m) != 0) 0 else 4;
+                        dest[y_idx] = f32ToBf16(dl2 * @as(f32, @floatFromInt(q_val - h_sub)));
+                        y_idx += 1;
+                    }
+
+                    shift += 2;
+                    m <<= 1;
+                }
+                q_ptr += 32;
+            }
+        }
+    }
+
+    /// Q5_K block structure (256 elements per block, 176 bytes)
+    /// Layout: d[2] + dmin[2] + scales[12] + qh[32] + qs[128]
+    const Q5_K_BLOCK = extern struct {
+        d: u16, // FP16 scale
+        dmin: u16, // FP16 min scale
+        scales: [12]u8, // quantized scales and mins
+        qh: [32]u8, // high bits
+        qs: [128]u8, // 4-bit quants (low 4 bits)
+    };
+
+    /// Dequantize Q5_K tensor to BF16
+    /// Reference: llama.cpp dequantize_row_q5_K
+    fn dequantizeQ5_K(self: *Self, info: GGUFTensorInfo, dest: []BF16) !void {
+        const src = self.getTensorData(info);
+        const n_elements = info.numElements();
+
+        if (dest.len < n_elements) return error.DestBufferTooSmall;
+
+        const QK_K = 256;
+        const nb = n_elements / QK_K;
+
+        const blocks: []const Q5_K_BLOCK = @as([*]const Q5_K_BLOCK, @ptrCast(@alignCast(src.ptr)))[0..nb];
+
+        for (blocks, 0..) |block, block_idx| {
+            const d = f16ToF32(block.d);
+            const min = f16ToF32(block.dmin);
+            const y_base: usize = block_idx * QK_K;
+
+            var y_idx: usize = y_base;
+            var qs_idx: usize = 0;
+            const qh_idx: usize = 0;
+
+            // Process in 64-element chunks (4 chunks per block)
+            for (0..4) |j| {
+                var sc: u8 = undefined;
+                var m: u8 = undefined;
+                getScaleMinK4(j * 2 + 0, block.scales, &sc, &m);
+                const d1 = d * @as(f32, @floatFromInt(sc));
+                const m1 = min * @as(f32, @floatFromInt(m));
+
+                getScaleMinK4(j * 2 + 1, block.scales, &sc, &m);
+                const d2 = d * @as(f32, @floatFromInt(sc));
+                const m2 = min * @as(f32, @floatFromInt(m));
+
+                // First 32 elements
+                for (0..32) |l| {
+                    const q_lo = block.qs[qs_idx + l] & 0xF;
+                    const q_hi: u8 = (block.qh[qh_idx + l] >> @intCast(j)) & 0x1;
+                    const q: u8 = q_lo | (q_hi << 4);
+                    dest[y_idx + l] = f32ToBf16(d1 * @as(f32, @floatFromInt(q)) - m1);
+                }
+
+                // Second 32 elements
+                for (0..32) |l| {
+                    const q_lo = block.qs[qs_idx + l] >> 4;
+                    const q_hi: u8 = (block.qh[qh_idx + l] >> @intCast(j + 4)) & 0x1;
+                    const q: u8 = q_lo | (q_hi << 4);
+                    dest[y_idx + 32 + l] = f32ToBf16(d2 * @as(f32, @floatFromInt(q)) - m2);
+                }
+
+                y_idx += 64;
+                qs_idx += 32;
+            }
+        }
+    }
+
